module signal_generator(
    input clk,
    input rst_n,
    output [4:0] wave
);

reg [4:0] wave_reg;
reg up;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        wave_reg <= 5'd0;
        up <= 1'b1;
    end
    else begin
        if (up) begin
            if (wave_reg == 5'd31)
                up <= 1'b0;
            else
                wave_reg <= wave_reg + 1'b1;
        end
        else begin
            if (wave_reg == 5'd0)
                up <= 1'b1;
            else
                wave_reg <= wave_reg - 1'b1;
        end
    end
end

assign wave = wave_reg;

endmodule
